    topLine.addColorStop(0.5,"rgba(201,168,76,0.6)");
    topLine.addColorStop(1,"transparent");
    ctx.strokeStyle=topLine;
    ctx.lineWidth=1;
    ctx.beginPath();ctx.moveTo(80,185);ctx.lineTo(W-80,185);ctx.stroke();

    // ── 主題標籤 ─────────────────────────────────
    var themeIcons={"工作":"💼","感情":"💕","抉擇":"⚖️","心靈":"🌙","財運":"✨","事業":"🌟"};
    var modeNames={1:"單張抽牌",2:"A/B決策",3:"三張牌陣",4:"時間軸牌陣",5:"月亮週期",10:"凱爾特十字"};
    var themeIcon=themeIcons[th2]||"🔮";

